import React from "react";

function Navbar() {
  return (
    <header className="navbar">
      <div className="container navbar-content">
        <div className="logo">Culinary Book</div>

        <nav className="nav-links">
          <a href="/">Home</a>
          <a href="/">Recipes</a>
          <a href="/">Categories</a>
          <a href="/">Favorites</a>
          <a href="/">Login</a>
        </nav>
      </div>
    </header>
  );
}

export default Navbar;
